<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Personal Expense Tracker</title>
    <style>
        :root {
            --primary: #2563eb;
            --danger: #dc2626;
            --bg: #f8fafc;
            --surface: #ffffff;
            --text: #1e293b;
            --border: #e2e8f0;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            background-color: var(--bg);
            color: var(--text);
            margin: 0;
            padding: 20px;
            line-height: 1.5;
        }

        .container {
            max-width: 800px;
            margin: 0 auto;
            background: var(--surface);
            padding: 2rem;
            border-radius: 8px;
            box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
        }

        h1 { margin-top: 0; font-size: 1.5rem; }
        h2 { font-size: 1.2rem; margin-bottom: 1rem; border-bottom: 2px solid var(--border); padding-bottom: 0.5rem;}

        /* Form Styles */
        .form-group { margin-bottom: 1rem; }
        label { display: block; font-weight: 600; margin-bottom: 0.25rem; font-size: 0.9rem; }

        input, select, textarea {
            width: 100%;
            padding: 0.5rem;
            border: 1px solid var(--border);
            border-radius: 4px;
            box-sizing: border-box; /* Ensures padding doesn't affect width */
        }

        button {
            cursor: pointer;
            font-weight: 600;
            border: none;
            border-radius: 4px;
            padding: 0.5rem 1rem;
            transition: opacity 0.2s;
        }
        button:hover { opacity: 0.9; }

        #add-expense { background-color: var(--primary); color: white; width: auto; display: inline-block;}

        #form-error {
            color: var(--danger);
            font-size: 0.85rem;
            margin-top: 0.25rem;
            min-height: 1.2em;
        }

        /* Filters */
        .filters {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
            gap: 1rem;
            margin-bottom: 2rem;
            padding: 1rem;
            background: #f1f5f9;
            border-radius: 6px;
        }

        /* List Styles */
        .expense-list { list-style: none; padding: 0; margin: 0; }

        .expense {
            display: grid;
            grid-template-columns: 1fr auto;
            gap: 1rem;
            padding: 1rem;
            border-bottom: 1px solid var(--border);
            align-items: center;
        }
        .expense:last-child { border-bottom: none; }

        .expense-info { display: flex; flex-direction: column; gap: 0.25rem; }
        .expense-amount { font-weight: bold; font-size: 1.1rem; color: var(--primary); }
        .expense-meta { font-size: 0.85rem; color: #64748b; }

        .exp-del {
            background-color: transparent;
            color: var(--danger);
            padding: 0.25rem 0.5rem;
            font-size: 0.85rem;
        }

        /* Summary Styles */
        .summary-section {
            margin-top: 2rem;
            padding-top: 1rem;
            border-top: 2px solid var(--border);
        }

        #total { font-size: 1.5rem; font-weight: bold; text-align: right; }

        .cat-totals { margin-top: 1rem; display: flex; flex-wrap: wrap; gap: 0.5rem; }
        .cat-total {
            background: #f1f5f9;
            padding: 0.25rem 0.5rem;
            border-radius: 4px;
            font-size: 0.85rem;
            border: 1px solid var(--border);
        }

        .empty-state { text-align: center; color: #64748b; padding: 2rem; }
    </style>
</head>
<body>

<div class="container">
    <h1>Expense Tracker</h1>

    <!-- Entry Form -->
    <form id="expense-form">
        <div class="form-group">
            <label for="amount">Amount ($)</label>
            <input type="number" id="amount" step="0.01" min="0.01" placeholder="e.g. 25.50" required>
        </div>

        <div class="form-group">
            <label for="category">Category</label>
            <select id="category" required>
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </div>

        <div class="form-group">
            <label for="date">Date</label>
            <input type="date" id="date" required>
        </div>

        <div class="form-group">
            <label for="note">Note (Optional)</label>
            <input type="text" id="note" placeholder="e.g. Weekly shopping">
        </div>

        <button type="submit" id="add-expense">Add Expense</button>
        <div id="form-error"></div>
    </form>

    <!-- Filters -->
    <div class="filters">
        <div class="form-group">
            <label for="filter-category">Category Filter</label>
            <select id="filter-category">
                <option value="all">All Categories</option>
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </div>

        <div class="form-group">
            <label for="filter-from">From Date</label>
            <input type="date" id="filter-from">
        </div>

        <div class="form-group">
            <label for="filter-to">To Date</label>
            <input type="date" id="filter-to">
        </div>
    </div>

    <!-- List -->
    <h2>Recent Expenses</h2>
    <ul id="expense-list" class="expense-list"></ul>

    <!-- Summary -->
    <div class="summary-section">
        <div style="display:flex; justify-content:space-between; align-items:center;">
            <span>Total (Visible):</span>
            <span id="total">$0.00</span>
        </div>
        <div id="cat-totals-container" class="cat-totals">
            <!-- Category totals injected here -->
        </div>
    </div>
</div>

<script>
    // --- State & DOM Elements ---
    const STORAGE_KEY = 'expense_tracker_data';

    let expenses = [];

    // Cache DOM elements for performance
    const els = {
        form: document.getElementById('expense-form'),
        amount: document.getElementById('amount'),
        category: document.getElementById('category'),
        date: document.getElementById('date'),
        note: document.getElementById('note'),
        submitBtn: document.getElementById('add-expense'),
        error: document.getElementById('form-error'),

        filterCategory: document.getElementById('filter-category'),
        filterFrom: document.getElementById('filter-from'),
        filterTo: document.getElementById('filter-to'),

        list: document.getElementById('expense-list'),
        totalDisplay: document.getElementById('total'),
        catTotalsContainer: document.getElementById('cat-totals-container')
    };

    // --- Initialization ---
    function init() {
        loadFromStorage();
        bindEvents();
        render();

        // Set default date to today for convenience
        els.date.valueAsDate = new Date();
    }

    function bindEvents() {
        // Form Submission
        els.form.addEventListener('submit', handleAddExpense);

        // Delete Buttons (Event Delegation)
        els.list.addEventListener('click', (e) => {
            if (e.target.classList.contains('exp-del')) {
                const row = e.target.closest('.expense');
                const id = row.dataset.id;
                deleteExpense(id);
            }
        });

        // Filter inputs change triggers re-render immediately
        els.filterCategory.addEventListener('change', render);
        els.filterFrom.addEventListener('change', render);
        els.filterTo.addEventListener('change', render);
    }

    // --- Core Logic ---

    function handleAddExpense(e) {
        e.preventDefault();

        const amountInput = parseFloat(els.amount.value);
        const dateVal = els.date.value;

        // Validation Rules:
        // 1. Amount must be non-empty, numeric, and > 0
        // 2. Date must not be missing

        if (isNaN(amountInput) || amountInput <= 0) {
            showError("Please enter a valid positive amount.");
            return;
        }

        if (!dateVal) {
            showError("Please select a date.");
            return;
        }

        // Success: Clear error and reset form (specifically amount as requested)
        els.error.textContent = "";
        els.amount.value = ""; 

        const newExpense = {
            id: Date.now().toString(), // Simple unique ID
            amount: amountInput,
            category: els.category.value,
            date: dateVal,
            note: els.note.value.trim() || ""
        };

        expenses.push(newExpense);
        saveToStorage();
        render();
    }

    function deleteExpense(id) {
        // Remove immediately
        expenses = expenses.filter(exp => exp.id !== id);
        saveToStorage();
        render();
    }

    function showError(msg) {
        els.error.textContent = msg;
    }

    function resetForm() {
        els.amount.value = "";
        els.note.value = "";
        // Keep date selected? Usually forms reset fully, but prompt says "resets the amount field". 
        // We leave other fields alone to allow quick re-entry.
    }

    // --- Rendering & Filtering ---

    function render() {
        const filterCat = els.filterCategory.value;
        const filterFrom = els.filterFrom.value;
        const filterTo = els.filterTo.value;

        // 1. Filter Logic
        let filteredExpenses = expenses.filter(exp => {
            // Category Filter
            if (filterCat !== 'all' && exp.category !== filterCat) return false;

            // Date Range Filter
            if (filterFrom && exp.date < filterFrom) return false;
            if (filterTo && exp.date > filterTo) return false;

            return true;
        });

        // 2. Sort Logic: Newest first
        filteredExpenses.sort((a, b) => new Date(b.date) - new Date(a.date));

        // 3. Render List
        renderList(filteredExpenses);

        // 4. Render Summary (Totals based on visible list)
        renderSummary(filteredExpenses);
    }

    function renderList(expenses) {
        els.list.innerHTML = '';

        if (expenses.length === 0) {
            els.list.innerHTML = '<li class="empty-state">No expenses found.</li>';
            return;
        }

        expenses.forEach(exp => {
            const li = document.createElement('li');
            li.className = 'expense';
            li.dataset.id = exp.id; // Store ID for deletion

            // Format date nicely
            const dateObj = new Date(exp.date);
            const formattedDate = dateObj.toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' });

            li.innerHTML = `
                <div class="expense-info">
                    <span class="expense-amount">$${exp.amount.toFixed(2)}</span>
                    <span class="expense-meta">
                        ${capitalize(exp.category)} • ${formattedDate}
                        ${exp.note ? `<br><span style="color:#64748b; font-style:italic;">"${exp.note}"</span>` : ''}
                    </span>
                </div>
                <button class="exp-del" aria-label="Delete expense">Delete</button>
            `;
            els.list.appendChild(li);
        });
    }

    function renderSummary(expenses) {
        // Calculate Total
        const total = expenses.reduce((sum, exp) => sum + exp.amount, 0);
        els.totalDisplay.textContent = `$${total.toFixed(2)}`;

        // Calculate Category Totals for visible items
        const catTotals = {};

        // Initialize categories with 0 if not present yet (to handle empty state gracefully)
        ['groceries', 'transport', 'bills', 'fun'].forEach(cat => {
            catTotals[cat] = 0; 
        });

        expenses.forEach(exp => {
            catTotals[exp.category] += exp.amount;
        });

        // Render Category Totals HTML
        els.catTotalsContainer.innerHTML = '';

        // Only show categories that have a total > 0 in the current view
        for (const [cat, amount] of Object.entries(catTotals)) {
            if (amount > 0) {
                const div = document.createElement('div');
                div.className = 'cat-total';
                div.setAttribute('data-cat', cat);
                div.textContent = `${capitalize(cat)}: $${amount.toFixed(2)}`;
                els.catTotalsContainer.appendChild(div);
            }
        }
    }

    // --- Utilities & Persistence ---

    function saveToStorage() {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    }

    function loadFromStorage() {
        const data = localStorage.getItem(STORAGE_KEY);
        if (data) {
            try {
                expenses = JSON.parse(data);
            } catch (e) {
                console.error("Failed to parse stored data", e);
                expenses = [];
            }
        }
    }

    function capitalize(str) {
        return str.charAt(0).toUpperCase() + str.slice(1);
    }

    // Start the app
    init();

</script>
</body>
</html>
